-- Insert 50 sandbag & non-traditional strength exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Sandbag Bear-Hug Squat', 'sandbag-bear-hug-squat-strength', 'A front-loaded sandbag squat held tight against the chest to build leg strength, trunk bracing, and upright position control.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A front-loaded sandbag squat held tight against the chest to build leg strength, trunk bracing, and upright position control.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (2/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'sandbag_bear_hug_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","rectus_abdominis","obliques","spinal_erectors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A front-loaded sandbag squat held tight against the chest to build leg strength, trunk bracing, and upright position control.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range."]}'::jsonb),
  ('Sandbag Front-Loaded Squat', 'sandbag-front-loaded-squat-strength', 'A front-loaded squat with the sandbag supported high on the chest/forearms to build bilateral leg strength and anterior core stiffness.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A front-loaded squat with the sandbag supported high on the chest/forearms to build bilateral leg strength and anterior core stiffness.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (2/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'sandbag_front_loaded_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","rectus_abdominis","obliques","spinal_erectors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A front-loaded squat with the sandbag supported high on the chest/forearms to build bilateral leg strength and anterior core stiffness.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range."]}'::jsonb),
  ('Sandbag Zercher Squat', 'sandbag-zercher-squat-strength', 'A crook-of-elbow sandbag squat that emphasizes trunk stiffness, upper-back tension, and controlled lower-body force production.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A crook-of-elbow sandbag squat that emphasizes trunk stiffness, upper-back tension, and controlled lower-body force production.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'sandbag_zercher_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","rectus_abdominis","obliques","spinal_erectors","lats"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A crook-of-elbow sandbag squat that emphasizes trunk stiffness, upper-back tension, and controlled lower-body force production.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range."]}'::jsonb),
  ('Sandbag Shoulder-Loaded Squat', 'sandbag-shoulder-loaded-squat-strength', 'A squat with the sandbag shouldered on one side, building leg strength plus anti-lateral-flexion trunk control.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A squat with the sandbag shouldered on one side, building leg strength plus anti-lateral-flexion trunk control.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'sandbag_shoulder_loaded_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","rectus_abdominis","obliques","spinal_erectors","lats"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A squat with the sandbag shouldered on one side, building leg strength plus anti-lateral-flexion trunk control.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range."]}'::jsonb),
  ('Sandbag Split Squat', 'sandbag-split-squat-strength', 'A stationary split squat with sandbag loading to build single-leg strength and hip/knee control without impact.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A stationary split squat with sandbag loading to build single-leg strength and hip/knee control without impact.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (2/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Unilateral Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'sandbag_split_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","calves","foot_intrinsics","rectus_abdominis","obliques"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A stationary split squat with sandbag loading to build single-leg strength and hip/knee control without impact.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range."]}'::jsonb),
  ('Front-Foot-Elevated Sandbag Split Squat', 'front-foot-elevated-sandbag-split-squat-strength', 'A range-building split squat with the front foot elevated and a sandbag load to strengthen deeper knee and hip positions.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A range-building split squat with the front foot elevated and a sandbag load to strengthen deeper knee and hip positions.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Unilateral Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'front_foot_elevated_sandbag_split_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","calves","foot_intrinsics","rectus_abdominis","obliques"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A range-building split squat with the front foot elevated and a sandbag load to strengthen deeper knee and hip positions.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range."]}'::jsonb),
  ('Sandbag Reverse Lunge', 'sandbag-reverse-lunge-strength', 'A backward-stepping lunge with sandbag loading that trains unilateral leg strength with less forward knee shear than many forward lunges.', 'BEGINNER', 8, 3, NULL, 20, 90, 35, 'A backward-stepping lunge with sandbag loading that trains unilateral leg strength with less forward knee shear than many forward lunges.', 'Primary subrole: squat_knee_dominant_strength. Strength is the main score. Explosiveness is secondary (2/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Sandbag Unilateral Lower-Body Strength', 'capacity', 'squat_knee_dominant_strength', 'sandbag_reverse_lunge_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control","loaded_gait","pelvic_control","trunk_anti_extension"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","calves","foot_intrinsics","rectus_abdominis","obliques"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A backward-stepping lunge with sandbag loading that trains unilateral leg strength with less forward knee shear than many forward lunges.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set feet and stance width before loading; use a range the athlete can own.","Mark the carry/drag distance and define a clean stop point."],"execution_steps":["Brace before descending.","Sit into the target range with knees tracking over toes.","Drive the floor away and stand tall without leaning or twisting.","Take short, controlled steps.","Keep ribs stacked over pelvis and avoid side-to-side sway.","Stop before posture, grip, or breathing quality breaks."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Knees track over laces.","Stand through the floor.","Tall posture, short strong steps.","Do not race the carry.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Knees collapse inward.","Depth exceeds controlled range.","Overstriding or wobbling under the load.","Turning the carry into a race."]}'::jsonb),
