lose.","Maintain a long spine and engaged lats.","Drive through the floor and finish with hips extended, not the low back arched.","Start each pull from a stable brace.","Pull with elbows and shoulder blades together, not the neck.","Control the return so tension stays in the target tissues."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Hips back, bag close.","Finish with glutes, not low back.","Pull elbows to pockets.","Shoulders stay active.","Get tight before the object leaves the floor."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Rounding through the low back.","Letting the load drift away.","Shrugging into the neck.","Using body swing instead of controlled pulling."]}'::jsonb),
  ('Yoke Carry', 'yoke-carry-strength', 'A heavy yoke walk that develops total-body bracing, hip strength, posture, and step discipline under axial load.', 'INTERMEDIATE', 8, 3, NULL, 20, 90, 35, 'A heavy yoke walk that develops total-body bracing, hip strength, posture, and step discipline under axial load.', 'Primary subrole: carry_trunk_loaded_bracing_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Yoke Loaded Carry Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'yoke_carry_strength', '{"primary_joint_actions":["loaded_gait","pelvic_control","trunk_anti_extension"],"primary_tissues":["gluteals","hamstrings","quadriceps","adductors","calves","foot_intrinsics","rectus_abdominis","obliques"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"low_to_moderate","impact_level":0}'::jsonb, '{"movement_description":"A heavy yoke walk that develops total-body bracing, hip strength, posture, and step discipline under axial load.","setup":["Select a yoke load the athlete can control without rushing or changing position.","Clear the training lane and confirm the athlete understands the start and finish position.","Mark the carry/drag distance and define a clean stop point."],"execution_steps":["Take short, controlled steps.","Keep ribs stacked over pelvis and avoid side-to-side sway.","Stop before posture, grip, or breathing quality breaks."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Tall posture, short strong steps.","Do not race the carry."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Overstriding or wobbling under the load.","Turning the carry into a race."]}'::jsonb),
  ('Jerry Can Farmer Carry', 'jerry-can-farmer-carry-strength', 'A two-hand odd-object farmer carry using heavy jerry cans or similar handled loads to build grip, trunk, and gait strength.', 'BEGINNER', 8, 3, NULL, 20, 90, 35, 'A two-hand odd-object farmer carry using heavy jerry cans or similar handled loads to build grip, trunk, and gait strength.', 'Primary subrole: carry_trunk_loaded_bracing_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Odd-Object Carry Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'jerry_can_farmer_carry_strength', '{"primary_joint_actions":["loaded_gait","pelvic_control","trunk_anti_extension"],"primary_tissues":["gluteals","hamstrings","calves","foot_intrinsics","rectus_abdominis","obliques","spinal_erectors","lats"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"low_to_moderate","impact_level":0}'::jsonb, '{"movement_description":"A two-hand odd-object farmer carry using heavy jerry cans or similar handled loads to build grip, trunk, and gait strength.","setup":["Select a jerry cans / odd-object handles load the athlete can control without rushing or changing position.","Clear the training lane and confirm the athlete understands the start and finish position.","Mark the carry/drag distance and define a clean stop point."],"execution_steps":["Take short, controlled steps.","Keep ribs stacked over pelvis and avoid side-to-side sway.","Stop before posture, grip, or breathing quality breaks."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Tall posture, short strong steps.","Do not race the carry."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Overstriding or wobbling under the load.","Turning the carry into a race."]}'::jsonb),
  ('Weighted Vest Push-Up', 'weighted-vest-push-up-strength', 'A push-up loaded with a weighted vest to build horizontal pressing strength, trunk stiffness, and shoulder control.', 'BEGINNER', 8, 3, 5, 30, 90, 40, 'A push-up loaded with a weighted vest to build horizontal pressing strength, trunk stiffness, and shoulder control.', 'Primary subrole: upper_body_push_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Weighted Vest Push Strength', 'capacity', 'upper_body_push_strength', 'weighted_vest_push_up_strength', '{"primary_joint_actions":["shoulder_horizontal_or_vertical_press","elbow_extension","scapular_control","trunk_bracing"],"primary_tissues":["rectus_abdominis","obliques","spinal_erectors","lats","trapezius","deltoids","rotator_cuff","forearm_flexors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"low_to_moderate","impact_level":0}'::jsonb, '{"movement_description":"A push-up loaded with a weighted vest to build horizontal pressing strength, trunk stiffness, and shoulder control.","setup":["Select a weighted vest load the athlete can control without rushing or changing position.","Secure the vest tightly so it does not shift during the rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Stack wrists, elbows, and shoulders; brace before pressing."],"execution_steps":["Create whole-body tension before the press.","Press through a controlled path without shrugging or flaring early.","Lock out with ribs down and shoulders controlled."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Press in a clean line.","Ribs down at lockout."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Rib flare or low-back arch during the press.","Shoulders dump forward at lockout."]}'::jsonb),
  ('Weighted Vest Pull-Up', 'weighted-vest-pull-up-strength', 'A strict pull-up with weighted vest loading to build vertical pulling, lat, upper-back, grip, and trunk strength.', 'INTERMEDIATE', 8, 3, 3, 20, 120, 25, 'A strict pull-up with weighted vest loading to build vertical pulling, lat, upper-back, grip, and trunk strength.', 'Primary subrole: pull_hang_grip_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Weighted Vest Pull Strength', 'capacity', 'pull_hang_grip_strength', 'weighted_vest_pull_up_strength', '{"primary_joint_actions":["shoulder_extension_or_adduction","elbow_flexion","scapular_retraction_depression","active_hang","grip_flexion","scapular_depression","trunk_bracing"],"primary_tissues":["rectus_abdominis","obliques","spinal_erectors","lats","trapezius","deltoids","rotator_cuff","forearm_flexors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"low_to_moderate","impact_level":0}'::jsonb, '{"movement_description":"A strict pull-up with weighted vest loading to build vertical pulling, lat, upper-back, grip, and trunk strength.","setup":["Select a weighted vest load the athlete can control without rushing or changing position.","Secure the vest tightly so it does not shift during the rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set shoulders active and avoid passive hanging or rounded pulling posture."],"execution_steps":["Start each pull from a stable brace.","Pull with elbows and shoulder blades together, not the neck.","Control the return so tension stays in the target tissues.","Start from active shoulders.","Use strict pulling or climbing mechanics without kicking for momentum."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Pull elbows to pockets.","Shoulders stay active."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Shrugging into the neck.","Using body swing instead of controlled pulling."]}'::jsonb),
  ('Strict Ring Dip', 'strict-ring-dip-strength', 'A controlled ring dip that develops pressing strength, shoulder stability, and body control through unstable support.', 'INTERMEDIATE', 8, 3, 5, 30, 90, 40, 'A controlled ring dip that develops pressing strength, shoulder stability, and body control through unstable support.', 'Primary subrole: upper_body_push_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Ring Push Strength', 'capacity', 'upper_body_push_strength', 'strict_ring_dip_strength', '{"primary_joint_actions":["shoulder_horizontal_or_vertical_press","elbow_extension","scapular_control","trunk_bracing"],"primary_tissues":["rectus_abdominis","obliques","spinal_erectors","lats","trapezius","deltoids","rotator_cuff","forearm_flexors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A controlled ring dip that develops pressing strength, shoulder stability, and body control through unstable support.","setup":["Select a gymnastic rings load the athlete can control without rushing or changing position.","Set ring height and strap length so both rings hang evenly.","Clear the training lane and confirm the athlete understands the start and finish position.","Stack wrists, elbows, and shoulders; brace before pressing."],"execution_steps":["Create whole-body tension before the press.","Press through a controlled path without shrugging or flaring early.","Lock out with ribs down and shoulders controlled."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Press in a clean line.","Ribs down at lockout."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Rib flare or low-back arch during the press.","Shoulders dump forward at lockout."]}'::jsonb),
  ('Feet-Elevated Ring Row', 'feet-elevated-ring-row-strength', 'A horizontal pulling exercise with feet elevated to increase bodyweight loading and upper-back strength demand.', 'INTERMEDIATE', 8, 3, 3, 20, 120, 25, 'A horizontal pulling exercise with feet elevated to increase bodyweight loading and upper-back strength demand.', 'Primary subrole: pull_hang_grip_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Ring Pull Strength', 'capacity', 'pull_hang_grip_strength', 'feet_elevated_ring_row_strength', '{"primary_joint_actions":["shoulder_extension_or_adduction","elbow_flexion","scapular_retraction_depression","trunk_bracing"],"primary_tissues":["rectus_abdominis","obliques","spinal_erectors","lats","trapezius","deltoids","rotator_cuff","forearm_flexors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A horizontal pulling exercise with feet elevated to increase bodyweight loading and upper-back strength demand.","setup":["Select a gymnastic rings load the athlete can control without rushing or changing position.","Set ring height and strap length so both rings hang evenly.","Clear the training lane and confirm the athlete understands the start and finish position.","Set shoulders active and avoid passive hanging or rounded pulling posture."],"execution_steps":["Start each pull from a stable brace.","Pull with elbows and shoulder blades together, not the neck.","Control the return so tension stays in the target tissues."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Pull elbows to pockets.","Shoulders stay active."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Shrugging into the neck.","Using body swing instead of controlled pulling."]}'::jsonb),
  ('Rope Climb with Foot Lock', 'rope-climb-with-foot-lock-strength', 'A controlled rope climb using a foot lock to build grip, pulling strength, trunk tension, and coordinated climbing positions.', 'INTERMEDIATE', 8, 3, 3, 20, 120, 25, 'A controlled rope climb using a foot lock to build grip, pulling strength, trunk tension, and coordinated climbing positions.', 'Primary subrole: pull_hang_grip_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.', 'Move the load with control, stay braced, and finish every rep in the same shape you started.', 'Rope Pull and Grip Strength', 'capacity', 'pull_hang_grip_strength', 'rope_climb_with_foot_lock_strength', '{"primary_joint_actions":["shoulder_extension_or_adduction","elbow_flexion","scapular_retraction_depression","active_hang","grip_flexion","scapular_depression","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","rectus_abdominis","obliques","spinal_erectors","lats","trapezius","deltoids"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"A controlled rope climb using a foot lock to build grip, pulling strength, trunk tension, and coordinated climbing positions.","setup":["Select a rope load the athlete can control without rushing or changing position.","Check rope security and give enough space for pulling or climbing without crowding.","Clear the training lane and confirm the athlete understands the start and finish position.","Set shoulders active and avoid passive hanging or rounded pulling posture."],"execution_steps":["Start each pull from a stable brace.","Pull with elbows and shoulder blades together, not the neck.","Control the return so tension stays in the target tissues.","Start from active shoulders.","Use strict pulling or climbing mechanics without kicking for momentum."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Pull elbows to pockets.","Shoulders stay active."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Shrugging into the neck.","Using body swing instead of controlled pulling."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

