-- Sandbag & non-traditional strength cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'sandbag_nontraditional_strength_readiness',
  NULL,
  'Sandbag and non-traditional strength without conditioning drift or wrong phase intent',
  'Sandbag, sled, tire, yoke, and other non-barbell Capacity strength must use intentional load, full rest, and strength-first scoring — not fatigue circuits, finisher races, or Output-speed intent.',
  'Sandbag and non-traditional strength cards span sandbag squat/hinge/push/pull/carry patterns plus sled, tire, yoke, rope, and vest loading for Capacity-phase force and tissue development without barbells, dumbbells, or kettlebells.',
  'Awkward and offset loading builds real-world force capacity and bracing. Poor placement, short rest, or mis-tagged explosiveness trains sloppy mechanics and steals from Output work.',
  'Place after Prepare & Access, Skill, and true Output when in the same session. Score Strength 5/5; cap Explosiveness at 1–2/5 only with crisp concentric intent, low fatigue, and full recovery.',
  'Do not program heavy sandbag or carry work after conditioning, use high-rep burnout sets, or tag strength lifts as explosiveness when delivery is fatigued or slow.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
